<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> trimmed </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> input</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">trim</span><span style="color:#9399B2;">();</span></span>
